# Each pending row first advances inside the loop body.
# `continue` re-enters the child subchain with that updated row, and only the
# final `break` emits back to the parent pipeline once the row reaches 3.
loop {
    _+1
    if _ >= 3 {
        break
    } else {
        continue
    }
}

